code = """import json
import re
import pandas as pd
import numpy as np

# Load clinical data
with open(locals()['var_function-call-11313423693512414189'], 'r') as f:
    clinical_data = json.load(f)

# Load molecular data
with open(locals()['var_function-call-13910111412887839427'], 'r') as f:
    molecular_data = json.load(f)

# Map Barcode -> Histology
barcode_to_hist = {}
# Regex to find TCGA barcode. It is 12 chars: TCGA-XX-XXXX
pattern = re.compile(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})')

for entry in clinical_data:
    desc = entry.get('Patient_description', '')
    hist = entry.get('histological_type', '')
    
    # Filter invalid histology (enclosed in brackets)
    if not hist or hist.startswith('[') or hist.endswith(']'):
        continue
        
    match = pattern.search(desc)
    if match:
        barcode = match.group(1)
        # Store in map. Note: if duplicates exist, last one wins, but histology should be constant for a patient.
        barcode_to_hist[barcode] = hist

# Process molecular data
data_list = []
for entry in molecular_data:
    barcode = entry.get('ParticipantBarcode')
    val_str = entry.get('normalized_count')
    
    if barcode and barcode in barcode_to_hist and val_str is not None:
        try:
            val = float(val_str)
            hist = barcode_to_hist[barcode]
            log_val = np.log10(val + 1)
            data_list.append({'histology': hist, 'log_val': log_val})
        except ValueError:
            continue

# Compute averages
if not data_list:
    print("__RESULT__:")
    print("{}")
else:
    df = pd.DataFrame(data_list)
    # Group by histology and mean
    result_df = df.groupby('histology')['log_val'].mean().reset_index()
    
    # Convert to dict with 4 decimal places
    final_dict = {
        row['histology']: round(row['log_val'], 4)
        for _, row in result_df.iterrows()
    }
    
    print("__RESULT__:")
    print(json.dumps(final_dict))"""

